var totalMoney = function(n) {
    const weeks = Math.floor(n / 7);
    const days = n % 7;
    let total = 0;
    for (let w = 0; w < weeks; w++) {
        total += 7 * (w + 1) + 21;
    }
    for (let d = 0; d < days; d++) {
        total += weeks + 1 + d;
    }
    return total;
};
